#include<cstdio>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int max(const int &x,const int &y){return x<y?y:x;}
inline int min(const int &x,const int &y){return x<y?x:y;}
inline void chkmax(int &x,const int &w){x<w?x=w:0;}
const int N=1e5+10,NK=110,INF=0x3f3f3f3f;int dp[N][NK],n,K,l[N],r[N],que[N],H=1,T;
struct Sort{int l,r;inline bool operator<(const Sort&Q)const{return l<Q.l;}}t[N];
inline void Work(){int lst=l[1],res(0);rep(1,n,i){res+=r[i]-lst;lst=l[i];}printf("%d\n",res);}
int main()
{
	int nn=read();K=read();rep(1,nn,i)t[i].l=read(),t[i].r=read();
	std::sort(t+1,t+nn+1);rep(1,nn,i){while(t[i].r<=t[i-1].r)++i,--K;l[++n]=t[i].l;r[n]=t[i].r;}
	if(!K)return Work(),0;memset(dp,~0x3f,sizeof(dp));rep(0,K,i)dp[i][i]=0;
	drep(-1,-n,k)
	{
		int x=k+1,mx=-INF;H=1;T=0;rep(0,min(K,n+k),j)
		{
			int i=j-k;while(H<=T&&r[que[H]]<=l[i])chkmax(mx,dp[que[H]][que[H]+x]),++H;
			if(r[i-1]<=l[i])chkmax(mx,dp[i-1][x+i-1]);else
			{
				while (H<=T&&dp[que[T]][x+que[T]]-r[que[T]]<=dp[i-1][x+i-1]-r[i-1])--T;que[++T]=i-1;
			}
			dp[i][j]=mx-l[i]+r[i];if(H<=T)chkmax(dp[i][j],dp[que[H]][x+que[H]]-r[que[H]]+r[i]);
		}
	}
	int ans=0;rep(n-K,n,i)chkmax(ans,dp[i][K-n+i]);printf("%d\n",ans);
}
